var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다! 제가 너무 일찍 왔나요?","JPN":"すみません！　ちょっと早く着きすぎましたかね？","ENG":"I'm sorry, am I too early?","TWN":"抱歉！我太早到了嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네? 헤헤, 고객님께서 부르신다길래 얼른 주문 받은 배달 마치고 왔죠!","JPN":"はい？　えへへ、お客様からのお呼びと聞いて、配達をそっこー終わらせて来ましたよ！","ENG":"Sorry? Heh heh. I came as soon as I finished delivering my last package for the day.","TWN":"嗯？哈哈～聽到客人找我，我就立刻把手邊的訂單完成衝過來囉！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그럼 황혼 여행은 어디로 갈까요? 제 손을 잡으면 원하시는 곳 어디로든 떠날 수 있어요!","JPN":"それじゃあ、新婚旅行はどこがいいですか？　私と手をつなげば、どこでも行けますよ！","ENG":"Now, where do you want to go for our retirement trip? Hold my hand, and I'll take you wherever you want!","TWN":"客人的退休之旅想去哪裡呢？只要牽著我的手，就可以想去哪裡就去哪裡！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"네? 아차, 또 제 생각이 너무 앞서 나갔죠?!","JPN":"え？　しまった、また早とちりしてしまったみたいですね！？","ENG":"Sorry? Oops, I thought too far ahead again, didn't I?","TWN":"欸？哎呀～現在談退休還太早嗎？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그렇지만 이 계약서를 받았다는 얘기는 고객님이랑 평생 함께하자는 뜻이잖아요?","JPN":"でも、この契約書を渡したってことは、お客様が私と一生一緒に過ごしたいという意味じゃないんですか？","ENG":"But this contract means I'll be with you for the rest of my life, right?","TWN":"可是收到這份契約，不就代表要和客人一起度過餘生嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"저는 언제나 남들보다 빨리빨리 달려 나갔지만, 이제는 속도를 좀 줄여 볼게요.","JPN":"私はいつも誰よりも速く走っていましたが、これからは少しスピードを落としたいと思います。","ENG":"I'm used to going ahead of everyone, but I'll try to keep up with you from now on.","TWN":"我總是跑得比其他人快，但現在我想要慢下來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앞만 보고 한달음에 달려가기보단 고객님과 한 발짝씩 함께 걸어갈 수 있게!","JPN":"前だけ見て一瞬で駆けつけるのではなく、お客様と一歩ずつ一緒に歩んでいけるように！","ENG":"Instead of running ahead, I'll walk alongside you from now on.","TWN":"因為我不想再跑跑跑向前跑，我想要細細感受和客人走的每一步路！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"다른 사람이랑 같은 풍경을 보고, 같은 주제로 얘기하고, 같이 웃는 것도 분명 재미있을 거 같아요.","JPN":"他の人と同じ風景を見て、同じ話題で話して、一緒に笑い合うのもきっと楽しいと思います。","ENG":"I think it'll be fun to do things with others.","TWN":"可以和另一個人看著相同的風景，聊著一樣的話題，一起開懷笑大，我想一定很有意思。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"전 항상 남들보다 너무 앞서 나가서 그런 적이 없거든요!","JPN":"いつも他の人より先に動いていたから、そういうのは経験したことがありません！","ENG":"I've always been so ahead of everyone else that I've never done anything with others.","TWN":"因為我總是跑在別人前頭，所以沒有這種經驗！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"으음, 느리게 흘러가는 세상은 익숙하지 않겠지만요.","JPN":"ううん、ゆっくり流れていく世界に慣れるまで、時間がかかりそうですね。","ENG":"Mm, it'll be difficult to get used to being slow, though.","TWN":"嗯…雖然我可能要適應一下世界越快，心則慢的新生活模式。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"이… 러… 면… 되… 나…?","JPN":"こう……話せば……いい……の……かな……？","ENG":"Like... thiiiis...?","TWN":"這…樣…夠…慢…嗎…？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아, 그렇게 느릴 필요 없다고요? 그래도 방금 피식 웃으셨죠?","JPN":"あ、ここまでゆっくりする必要はないですか？　でも今、クスッと笑いましたね？","ENG":"Oh, I don't have to be so slow. But I made you laugh, didn't I?","TWN":"喔，不用這麼慢喔？但你剛有笑吧？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"어쨌거나 미소 배달 성공! 한 건 올린 셈 칠게요, 고객님!","JPN":"とにかく微笑みの配達成功！　また1件実績が増えたってことでいいですね、お客様？","ENG":"I brought a smile to your face. That's one more successful delivery in my record!","TWN":"總之外送笑容成功！我要算業績喔！哈哈～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};